mapper.select:
/* 카테고리 목록 조회 library.selectCategoryList */ SELECT CATEGORY_ID , USER_ID , CATEGORY_NM , COLOR , SORT_ORD , CREATE_DT FROM TB_KNOW_CAT WHERE 1=1
AND USER_ID = #{userId}
ORDER BY SORT_ORD, CREATE_DT DESC

/* 카드 목록 조회 library.selectCardList */ SELECT CARD_ID , USER_ID , CATEGORY_ID , LOG_ID , SVC_TY , TITLE , TAGS , PIN_YN , ARCHIVE_YN , ARCHIVE_DT , SORT_ORD , SQL_CODE , NEW_YN , THUMB_IMG , USE_YN , CREATE_DT , MODIFY_DT FROM TB_KNOW_CARD WHERE 1=1
AND USER_ID = #{userId}
AND CATEGORY_ID = #{categoryId}
AND USE_YN = #{useYn}
AND ARCHIVE_YN = #{archiveYn}
AND (TITLE LIKE CONCAT('%', #{searchTitle}, '%') OR TAGS LIKE CONCAT('%', #{searchTitle}, '%'))
ORDER BY SORT_ORD
ORDER BY CREATE_DT DESC
ORDER BY TITLE
ORDER BY PIN_YN DESC, SORT_ORD
ORDER BY SORT_ORD

